const HAZARD_TYPES_V2 = [
{ id:"asbestos",icon:"☣️",label:"Asbestos",severity:"critical",color:"#ef4444",
instructions:["DO NOT DISTURB — certified abatement specialist required","Seal area before any work","N100 respirator + full body suit mandatory"] },
{ id:"lead_paint",icon:"⚠️",label:"Lead Paint",severity:"high",color:"#f97316",
instructions:["Wear N95 respirator + gloves","Contain dust with HEPA vacuum","No dry sanding without containment"] },
{ id:"mold",icon:"🟠",label:"Toxic Mold",severity:"high",color:"#f97316",
instructions:["N95 respirator required","Contain area with plastic sheeting","HEPA air scrubber recommended"] },
{ id:"aggressive_dog",icon:"🐕",label:"Aggressive Dog",severity:"warning",color:"#f59e0b",
instructions:["Call client before arrival","Do not enter if dog is loose","Keep equipment bags closed"] },
{ id:"aggressive_pet",icon:"🐾",label:"Aggressive Pet",severity:"warning",color:"#f59e0b",
instructions:["May scratch or bite without warning","Request client to confine pet","Thick gloves recommended"] },
{ id:"confined_space",icon:"⚠",label:"Confined Space",severity:"critical",color:"#ef4444",
instructions:["Entry permit required","Two-person rule — never enter alone","Continuous gas monitoring mandatory","Harness and ventilation required"] },
{ id:"electrical_hazard",icon:"⚡",label:"Electrical Hazard",severity:"high",color:"#f97316",
instructions:["Lockout/tagout before any work","Test with non-contact voltage tester","Insulated tools only"] },
{ id:"gas_leak",icon:"💨",label:"Gas Leak",severity:"critical",color:"#ef4444",
instructions:["EVACUATE IMMEDIATELY","Call utility company","No open flames or sparks","No electrical switches"] },
{ id:"trap_neutrals",icon:"⚠️",label:"Trap Neutrals",severity:"high",color:"#f97316",
instructions:["Test before touching any wire","Non-contact voltage tester on ALL neutrals","Isolate circuit at panel"] },
{ id:"biohazard",icon:"☣️",label:"Biohazard",severity:"critical",color:"#ef4444",
instructions:["Full PPE required","Double-bag contaminated materials","Decontaminate all tools before leaving"] },
{ id:"propane",icon:"🔥",label:"Propane",severity:"high",color:"#f97316",
instructions:["Check connections with soap solution","No open flames within 10 feet","Ensure adequate ventilation"] },
];
const SEVERITY_CONFIG = {
critical:{ label:"CRITICAL",color:"#ef4444",bg:"rgba(239,68,68,.12)",badge:"STOP WORK" },
high: { label:"HIGH", color:"#f97316",bg:"rgba(249,115,22,.1)", badge:"PPE REQ" },
warning: { label:"WARNING", color:"#f59e0b",bg:"rgba(245,158,11,.1)", badge:"CAUTION" },
info: { label:"INFO", color:"#3b82f6",bg:"rgba(59,130,246,.1)", badge:"NOTE" },
};
function HazardAlert({ hazardId }) {
const info = HAZARD_TYPES_V2.find(h => h.id === hazardId);
if (!info) return null;
const sev = SEVERITY_CONFIG[info.severity] || SEVERITY_CONFIG.warning;
return (
<div style={{ background:sev.bg,border:"2px solid "+sev.color,borderRadius:10,padding:"10px 14px",marginBottom:8 }}>
<div className="rowb" style={{ marginBottom:8 }}>
<div style={{ display:"flex",alignItems:"center",gap:10 }}>
<span style={{ fontSize:20 }}>{info.icon}</span>
<div>
<div style={{ fontWeight:800,fontSize:13,color:sev.color }}>{info.label}</div>
<div style={{ fontSize:10,color:sev.color,opacity:.8,letterSpacing:.5,fontWeight:700 }}>{sev.label}</div>
</div>
</div>
<span style={{ background:sev.color,color:"#fff",borderRadius:20,padding:"2px 9px",fontSize:10,fontWeight:900 }}>{sev.badge}</span>
</div>
<ul style={{ margin:0,paddingLeft:18,fontSize:12,lineHeight:1.7,color:"var(--text)" }}>
{info.instructions.map((inst,i) => <li key={i}>{inst}</li>)}
</ul>
</div>
);
}
function HazardInstructions({ hazards }) {
if (!hazards || !hazards.length) return null;
const sevOrder = { critical:0,high:1,warning:2,info:3 };
const sorted = [...hazards].sort((a,b) => {
const aInfo = HAZARD_TYPES_V2.find(h => h.id === a);
const bInfo = HAZARD_TYPES_V2.find(h => h.id === b);
return (sevOrder[(aInfo || {}).severity] || 3) - (sevOrder[(bInfo || {}).severity] || 3);
});
const hasCritical = sorted.some(h => { const i = HAZARD_TYPES_V2.find(t => t.id === h); return i && i.severity === "critical"; });
return (
<div style={{ marginTop:8 }}>
{hasCritical && (
<div style={{ background:"rgba(239,68,68,.15)",border:"2px solid #ef4444",borderRadius:10,padding:"8px 14px",marginBottom:10,display:"flex",alignItems:"center",gap:8 }}>
<span style={{ fontSize:18 }}> </span>
<div style={{ fontWeight:900,color:"#ef4444",fontSize:12 }}>CRITICAL HAZARD — Read all instructions before entering site</div>
</div>
)}
{sorted.map(h => <HazardAlert key={h} hazardId={h} />)}
</div>
);
}
