/* ████████████████████████████████████████████████████████████████████████████
V10 SYSTEM 1 - CLOUD STORAGE CLIENT
Signed URL upload flow, background queue, thumbnail requests, media metadata
Set CLOUD_CONFIG.mediaApiUrl to activate. Demo mode uses blob: URLs.
████████████████████████████████████████████████████████████████████████████ */
const CLOUD_CFG = {
mediaApiUrl: "", // e.g. "https://media-api.yourcompany.com"
provider: "r2",
bucket: "tangible-media",
};
const CloudStorage = (() => {
function isDemoMode() { return !CLOUD_CFG.mediaApiUrl; }
async function getSignedPutUrl({ filename, mimeType, cloudKey, accessToken }) {
const r = await fetch(CLOUD_CFG.mediaApiUrl + "/sign", {
method: "POST",
headers: { "Content-Type": "application/json", ...(accessToken ? { Authorization: "Bearer " + accessToken } : {}) },
body: JSON.stringify({ filename, mimeType, cloudKey }),
});
if (!r.ok) throw new Error("Sign failed: " + r.status);
return r.json(); // { uploadUrl, cloudKey, expiresIn }
}
async function putToCloud(uploadUrl, file, mimeType, onProgress) {
return new Promise((resolve, reject) => {
const xhr = new XMLHttpRequest();
xhr.upload.onprogress = (e) => { if (e.lengthComputable && onProgress) onProgress(Math.round((e.loaded / e.total) * 100)); };
xhr.onload = () => (xhr.status >= 200 && xhr.status < 300 ? resolve() : reject(new Error("Upload HTTP " + xhr.status)));
xhr.onerror = () => reject(new Error("Network error"));
xhr.open("PUT", uploadUrl);
xhr.setRequestHeader("Content-Type", mimeType);
xhr.send(file);
});
}
async function requestThumbnail({ cloudKey, mediaId, accessToken }) {
if (!CLOUD_CFG.mediaApiUrl) return;
await fetch(CLOUD_CFG.mediaApiUrl + "/thumb", {
method: "POST",
headers: { "Content-Type": "application/json", ...(accessToken ? { Authorization: "Bearer " + accessToken } : {}) },
body: JSON.stringify({ cloudKey, mediaId }),
}).catch(() => {});
}
async function uploadFile({ file, filename, mimeType, jobId, clientId, propertyId, caption, accessToken, onProgress, db }) {
const mediaId = makeId("media");
const ext = filename.split(".").pop();
const cloudKey = "media/" + mediaId + "." + ext;
if (isDemoMode()) {
const blobUrl = URL.createObjectURL(file);
const doc = {
_id: mediaId, type: "media_meta", cloudKey, filename, mimeType,
url: blobUrl, thumbUrl: null, jobId: jobId || null,
clientId: clientId || null, propertyId: propertyId || null,
caption: caption || "", status: "local", size: file.size,
createdAt: now(), updatedAt: now(),
};
if (db) await db.put(doc);
return doc;
}
// Live mode: signed PUT flow
const { uploadUrl } = await getSignedPutUrl({ filename, mimeType, cloudKey, accessToken });
await putToCloud(uploadUrl, file, mimeType, onProgress);
const cloudUrl = CLOUD_CFG.mediaApiUrl + "/files/" + cloudKey;
const doc = {
_id: mediaId, type: "media_meta", cloudKey, filename, mimeType,
url: cloudUrl, thumbUrl: null, jobId: jobId || null,
clientId: clientId || null, propertyId: propertyId || null,
caption: caption || "", status: "uploaded", size: file.size,
createdAt: now(), updatedAt: now(),
};
if (db) await db.put(doc);
await requestThumbnail({ cloudKey, mediaId, accessToken });
return doc;
}
async function deleteFile({ cloudKey, mediaId, db }) {
if (db) {
const doc = await db.get(mediaId).catch(() => null);
if (doc) await db.put({ ...doc, _deleted: true, updatedAt: now() });
}
if (!isDemoMode()) {
await fetch(CLOUD_CFG.mediaApiUrl + "/files/" + cloudKey, { method: "DELETE" }).catch(() => {});
}
}
return { isDemoMode, uploadFile, deleteFile };
})();
// -- Upload Queue (IndexedDB-backed, survives refresh) ----------------------
class UploadQueue {
constructor() {
this._db = null;
this._subs = [];
}
async _open() {
if (this._db) return this._db;
return new Promise((res, rej) => {
const req = indexedDB.open("sp_upload_queue", 1);
req.onupgradeneeded = e => e.target.result.createObjectStore("queue", { keyPath: "id" });
req.onsuccess = e => { this._db = e.target.result; res(this._db); };
req.onerror = () => rej(req.error);
});
}
async enqueue(entry) {
const db = await this._open();
const item = { ...entry, id: makeId("uq"), status: "queued", progress: 0, addedAt: now() };
const tx = db.transaction("queue", "readwrite");
tx.objectStore("queue").add(item);
await new Promise(r => { tx.oncomplete = r; });
this._notify();
return item;
}
async getAll() {
const db = await this._open();
return new Promise(res => {
const tx = db.transaction("queue", "readonly");
const req = tx.objectStore("queue").getAll();
req.onsuccess = () => res(req.result || []);
});
}
async update(id, changes) {
const db = await this._open();
const tx = db.transaction("queue", "readwrite");
const st = tx.objectStore("queue");
const get = st.get(id);
get.onsuccess = () => { if (get.result) st.put({ ...get.result, ...changes }); };
await new Promise(r => { tx.oncomplete = r; });
this._notify();
}
async remove(id) {
const db = await this._open();
const tx = db.transaction("queue", "readwrite");
tx.objectStore("queue").delete(id);
await new Promise(r => { tx.oncomplete = r; });
this._notify();
}
subscribe(fn) { this._subs.push(fn); return () => { this._subs = this._subs.filter(s => s !== fn); }; }
_notify() { this.getAll().then(items => this._subs.forEach(fn => fn(items))); }
}
const uploadQueue = new UploadQueue();
function useUploadQueue() {
const [queue, setQueue] = useState([]);
useEffect(() => {
uploadQueue.getAll().then(setQueue);
return uploadQueue.subscribe(setQueue);
}, []);
return queue;
}
function useMediaUpload({ jobId, clientId, propertyId } = {}) {
const { db } = useDb();
const queue = useUploadQueue();
const upload = useCallback(async (files) => {
const arr = Array.from(files);
for (const file of arr) {
const entry = await uploadQueue.enqueue({ filename: file.name, mimeType: file.type, jobId, clientId, propertyId, fileRef: file });
await uploadQueue.update(entry.id, { status: "uploading" });
try {
await CloudStorage.uploadFile({
file, filename: file.name, mimeType: file.type,
jobId, clientId, propertyId, db,
onProgress: (pct) => uploadQueue.update(entry.id, { progress: pct }),
});
await uploadQueue.remove(entry.id);
} catch (err) {
await uploadQueue.update(entry.id, { status: "error", error: err.message });
}
}
}, [db, jobId, clientId, propertyId]);
return { upload, queue };
}
function UploadQueuePanel() {
const queue = useUploadQueue();
if (!queue.length) return null;
return (
<div style={{ position:"fixed", bottom:90, right:16, width:280, background:"var(--surface)", border:"2px solid var(--border)", borderRadius:12, padding:12, zIndex:9000, boxShadow:"var(--shadow-lg)" }}>
<div style={{ fontSize:11, fontWeight:900, color:"var(--muted)", marginBottom:8, letterSpacing:.5 }}>UPLOADS ({queue.length})</div>
{queue.map(item => (
<div key={item.id} style={{ marginBottom:8 }}>
<div className="rowb" style={{ marginBottom:4 }}>
<span style={{ fontSize:12, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", maxWidth:180 }}>{item.filename}</span>
<span style={{ fontSize:11, color: item.status === "error" ? "var(--red)" : "var(--muted)" }}>
{item.status === "error" ? "Failed" : item.status === "uploading" ? item.progress + "%" : "Queued"}
</span>
</div>
<div style={{ height:3, background:"var(--s2)", borderRadius:2 }}>
<div style={{ height:3, background: item.status === "error" ? "var(--red)" : "var(--accent)", borderRadius:2, width: item.progress + "%", transition:"width .3s" }} />
</div>
</div>
))}
</div>
);
}
