/* ████████████████████████████████████████████████████████████████████████████
V11 MODULE 3 - REVENUE AUTOPILOT ENGINE
Trigger scanning · opportunity generation · AI drafting · CRM push
████████████████████████████████████████████████████████████████████████████ */
const AUTOPILOT_TRIGGER_TYPES = {
expired_warranty: { label: "Expired Warranty", icon: " ", color: "var(--red)", priority: "high" },
overdue_maintenance: { label: "Overdue Maintenance", icon: " ", color: "var(--orange)", priority: "high" },
inactive_client: { label: "Inactive Client", icon: " ", color: "var(--yellow)", priority: "medium" },
equipment_age: { label: "Aging Equipment", icon: "⚙", color: "var(--orange)", priority: "medium" },
upgrade_opportunity: { label: "Upgrade Opportunity", icon: " ", color: "var(--accent)", priority: "low" },
expiring_soon: { label: "Warranty Expiring", icon: " ", color: "var(--yellow)", priority: "medium" },
};
function useRevenueAutopilot(clients, invoices, appts) {
const scanOpportunities = useCallback(() => {
const opps = [];
const now_str = new Date().toISOString().slice(0, 10);
const cutoff = new Date();
cutoff.setMonth(cutoff.getMonth() - 6);
const inactiveCutoff = cutoff.toISOString().slice(0, 10);
clients.forEach(client => {
const id = client.id || client._id;
const w = client.warranty || {};
const sub = client.subscription || {};
const clientInvs = invoices.filter(inv => inv.clientId === id);
const lastJob = clientInvs.sort((a,b) => (b.date||"").localeCompare(a.date||"")).slice(0,1)[0];
// Expired warranty
if (w.active === false || (w.expiry && w.expiry < now_str)) {
opps.push({ clientId: id, client, type: "expired_warranty",
title: "Renew " + (w.plan || "Warranty"),
detail: "Warranty expired " + (w.expiry || "—") + ". Offer renewal.",
estimatedValue: 299, priority: "high" });
}
// Expiring soon (within 60 days)
if (w.active && w.expiry) {
const daysLeft = Math.floor((new Date(w.expiry) - new Date()) / 86400000);
if (daysLeft > 0 && daysLeft < 60) {
opps.push({ clientId: id, client, type: "expiring_soon",
title: "Warranty Renews in " + daysLeft + " days",
detail: "Proactive renewal before expiry: " + w.expiry,
estimatedValue: 199, priority: "medium" });
}
}
// Inactive client (no invoice in 6 months)
if (!lastJob || (lastJob.date || "") < inactiveCutoff) {
opps.push({ clientId: id, client, type: "inactive_client",
title: "Re-engage " + client.name,
detail: "Last service: " + (lastJob ? lastJob.date : "never") + ". Send a check-in offer.",
estimatedValue: 150, priority: "medium" });
}
// No subscription
if (!sub.active) {
opps.push({ clientId: id, client, type: "upgrade_opportunity",
title: "No Maintenance Plan",
detail: client.name + " has no active subscription. Offer starter plan.",
estimatedValue: 89, priority: "low" });
}
});
// Overdue maintenance (appts older than 6 months with no follow-up)
const oldAppts = appts.filter(a => a.date < inactiveCutoff);
oldAppts.forEach(a => {
const recentFollowup = appts.find(b =>
b.clientId === a.clientId && b.date > inactiveCutoff);
if (!recentFollowup) {
const cl = clients.find(c => (c.id||c._id) === a.clientId);
if (cl && !opps.find(o => o.clientId === a.clientId && o.type === "overdue_maintenance")) {
opps.push({ clientId: a.clientId, client: cl, type: "overdue_maintenance",
title: "Overdue: " + a.service,
detail: "Last visited " + a.date + ". Schedule follow-up.",
estimatedValue: 180, priority: "high" });
}
}
});
return opps.sort((a,b) => {
const order = { high: 0, medium: 1, low: 2 };
return (order[a.priority] || 1) - (order[b.priority] || 1);
});
}, [clients, invoices, appts]);
return { scanOpportunities };
}
