/* -- PROPERTY RISK SCORING ------------------------------------------------ */
function PropertyRiskPage({ clients }) {
var { properties } = useProperties({ clientId: null });
// Risk model: score 0-100 based on age, hazards, permit status
var scoredProperties = (properties || []).map(function(prop) {
var score = 0;
var yearBuilt = parseInt(prop.yearBuilt || '2000');
var age = new Date().getFullYear() - yearBuilt;
if (age > 30) score += 30;
else if (age > 15) score += 15;
if (prop.hazards && prop.hazards.length > 0) score += prop.hazards.length * 10;
if (!prop.lastInspection) score += 20;
var level = score >= 60 ? 'HIGH' : score >= 30 ? 'MEDIUM' : 'LOW';
var color = score >= 60 ? 'var(--red)' : score >= 30 ? 'var(--orange)' : 'var(--green)';
return { ...prop, riskScore: score, riskLevel: level, riskColor: color };
}).sort(function(a,b){ return b.riskScore - a.riskScore; });
return (
<div className="fade">
<div style={{ marginBottom:16 }}>
<div style={{ fontSize:18, fontWeight:800 }}>Property Risk Assessment</div>
<div style={{ fontSize:12, color:'var(--muted)' }}>Risk scored by age, hazards, inspection history · {scoredProperties.length} properties</div>
</div>
<div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:10, marginBottom:16 }}>
{['HIGH','MEDIUM','LOW'].map(function(level) {
var count = scoredProperties.filter(function(p){ return p.riskLevel===level; }).length;
var color = level==='HIGH'?'var(--red)':level==='MEDIUM'?'var(--orange)':'var(--green)';
return <div key={level} className="card" style={{ padding:'12px 14px',textAlign:'center' }}><div style={{ fontSize:22,fontWeight:900,color:color }}>{count}</div><div style={{ fontSize:10,color:'var(--muted)',fontWeight:700 }}>{level} RISK</div></div>;
})}
</div>
{scoredProperties.length===0 && <div style={{ textAlign:'center',padding:'32px 0',color:'var(--muted)' }}>No properties found. Add properties to see risk assessments.</div>}
{scoredProperties.map(function(prop) {
var cl = clients.find(function(c){ return (c.id||c._id)===prop.clientId; });
return (
<div key={prop._id||prop.id} className="card" style={{ padding:'12px 14px', marginBottom:8, borderLeft:'3px solid '+prop.riskColor }}>
<div className="rowb">
<div>
<div style={{ fontWeight:800, fontSize:13 }}>{prop.address || 'Property'}</div>
<div style={{ fontSize:11, color:'var(--muted)' }}>{cl?cl.name:'?'} · Built {prop.yearBuilt||'unknown'}</div>
<div style={{ display:'flex', gap:6, marginTop:6 }}>
{prop.hazards && prop.hazards.slice(0,3).map(function(h,i){ return <span key={i} style={{ fontSize:10,padding:'2px 6px',borderRadius:20,background:'rgba(239,68,68,.15)',color:'var(--red)' }}>{h}</span>; })}
</div>
</div>
<div style={{ textAlign:'right' }}>
<div style={{ fontSize:24, fontWeight:900, color:prop.riskColor }}>{prop.riskScore}</div>
<div style={{ fontSize:11, fontWeight:800, color:prop.riskColor, background:prop.riskColor+'22', padding:'2px 8px', borderRadius:20 }}>{prop.riskLevel}</div>
</div>
</div>
<div style={{ height:4, background:'var(--s2)', borderRadius:2, marginTop:10 }}>
<div style={{ height:4, borderRadius:2, background:prop.riskColor, width:Math.min(100,prop.riskScore)+'%' }} />
</div>
</div>
);
})}
</div>
);
}
