/* ======================================================================
MODULE H - WORKFLOW STEPPER COMPONENT
====================================================================== */
function WorkflowStepper({ appt, onTransition, loading = false }) {
const { transition, JOB_STATUSES: STATUSES, JOB_TRANSITIONS: TRANS } = useJobWorkflow();
const [note, setNote] = useState('');
const [confirming, setConfirming] = useState(null);
const currentStatus = appt.workflowStatus || 'assigned';
const current = STATUSES.find(s => s.id === currentStatus) || STATUSES[0];
const nextStatuses = STATUSES.filter(s => (TRANS[currentStatus]||[]).includes(s.id));
async function handleTransition(newStatus) {
setConfirming(newStatus);
try {
const changes = await transition(appt, newStatus, { note });
if (changes) onTransition && onTransition(appt.id, changes);
setNote('');
} finally { setConfirming(null); }
}
if (!appt) return null;
return (
<div className="wf-stepper">
{!navigator.onLine && (
<div className="offline-pill" style={{marginBottom:4}}> Offline — changes save locally, sync when connected</div>
)}
{/* Current status */}
<div className="wf-current" style={{ borderColor: current.color }}>
<span className="wf-icon">{current.icon}</span>
<div>
<div className="wf-cur-label" style={{ color: current.color }}>{current.label}</div>
{(appt.statusLog||[]).length > 0 && (
<div className="wf-cur-time">
since {new Date(appt.statusLog[appt.statusLog.length-1].timestamp).toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'})}
</div>
)}
</div>
</div>
{/* Transition buttons */}
{nextStatuses.length > 0 && (
<>
<div className="wf-actions">
{nextStatuses.map(s => (
<button key={s.id} className="wf-btn" style={{ background: s.color }} disabled={loading || !!confirming} onClick={() => handleTransition(s.id)}>
{confirming === s.id ? '...' : (s.icon) + " " + (s.label)}
</button>
))}
</div>
<div className="fg" style={{marginTop:-4}}>
<label style={{fontSize:11}}>Note (optional)</label>
<input className="inp" placeholder="Add status note..." value={note} onChange={e=>setNote(e.target.value)} />
</div>
</>
)}
{!nextStatuses.length && currentStatus !== 'cancelled' && (
<div style={{ textAlign:'center', padding:'8px 0', color:'var(--accent)', fontWeight:700 }}>✔ Job Complete</div>
)}
{/* Timeline */}
{(appt.statusLog||[]).length > 0 && (
<div className="wf-timeline">
{appt.statusLog.map((entry, i) => {
const cfg = STATUSES.find(s => s.id === entry.status);
return (
<div key={i} className="wf-trow">
<span className="wf-tdot" style={{ background: cfg ? (cfg.color || 'var(--muted)') : 'var(--muted)' }} />
<span style={{ fontWeight:700, fontSize:12 }}>{cfg.label || entry.status}</span>
<span style={{ color:'var(--muted)', fontSize:11, marginLeft:6 }}>{new Date(entry.timestamp).toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'})}</span>
{entry.geo && <span style={{ color:'var(--muted)', fontSize:10, marginLeft:4 }}> </span>}
{entry.note && <span style={{ color:'var(--muted)', fontSize:11, marginLeft:4 }}>"{entry.note}"</span>}
</div>
);
})}
</div>
)}
</div>
);
}
/* ======================================================================
MODULE I - ENHANCED INVENTORY WITH STOCK LAYERS
====================================================================== */
function InventoryStockPanel({ products, vehicles }) {
const { stockMap, adjustStock, getStock } = useInventoryDb();
const [adjItem, setAdjItem] = useState(null);
const [adjQty, setAdjQty] = useState('');
const [adjLoc, setAdjLoc] = useState('warehouse');
const [adjNote, setAdjNote] = useState('');
const [tab, setTab] = useState('warehouse');
const lowStockItems = products.filter(p => p.stock !== null && p.stock < 25);
function openAdj(p) { setAdjItem(p); setAdjQty(''); setAdjLoc('warehouse'); setAdjNote(''); }
async function applyAdj() {
if (!adjItem || !adjQty) return;
await adjustStock(adjItem.id, adjLoc, Number(adjQty));
setAdjItem(null);
}
const TABS = ['warehouse', 'vehicles', 'low_stock'];
return (
<div style={{ marginTop: 16 }}>
<div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:12 }}>
<div style={{ fontWeight:800, fontSize:15 }}>Stock Levels</div>
{lowStockItems.length > 0 && (
<div className="low-stock-alert" style={{ padding:'6px 12px', marginBottom:0, fontSize:12 }}>
⚠ {lowStockItems.length} item{lowStockItems.length!==1?'s':''} low
</div>
)}
</div>
<div className="prop-detail-tabs" style={{ marginBottom:12 }}>
{TABS.map(t => (
<button key={t} className={"pdt-btn" + (tab===t?' active':'')} onClick={()=>setTab(t)}>
{t==='warehouse'?' Warehouse':t==='vehicles'?' Vehicles':'⚠ Low Stock'}
{t==='low_stock' && lowStockItems.length > 0 && <span style={{ marginLeft:4, background:'var(--red)', color:'#fff', borderRadius:10, padding:'0 6px', fontSize:10 }}>{lowStockItems.length}</span>}
</button>
))}
</div>
{tab === 'warehouse' && (
<div className="card" style={{ padding:0, overflow:'hidden' }}>
<table className="stock-table">
<thead><tr><th>Product</th><th>Category</th><th>Warehouse Qty</th><th>Unit</th><th>Action</th></tr></thead>
<tbody>
{products.filter(p=>p.stock!==null).map(p => {
const wQty = p.stock + getStock(p.id, 'warehouse');
const cls = wQty < 10 ? 'qty-low' : wQty < 25 ? 'qty-warn' : 'qty-ok';
return (
<tr key={p.id}>
<td style={{fontWeight:700}}>{p.name}</td>
<td><span className="badge b-gray">{p.category}</span></td>
<td className={cls}>{wQty} {p.unit}</td>
<td style={{color:'var(--muted)'}}>{p.unit}</td>
<td><button className="btn btn-ghost btn-sm" onClick={() => openAdj(p)}>Adjust</button></td>
</tr>
);
})}
</tbody>
</table>
</div>
)}
{tab === 'vehicles' && (
<div>
{vehicles.map(v => (
<div key={v.id} style={{ marginBottom:16 }}>
<div style={{ fontWeight:800, marginBottom:8, display:'flex', alignItems:'center', gap:8 }}>
{v.make} {v.model} <span style={{color:'var(--muted)',fontSize:12}}>({v.plate})</span>
</div>
{(v.inventory||[]).length > 0 ? (
<div className="card" style={{padding:0,overflow:'hidden'}}>
<table className="stock-table">
<thead><tr><th>Part</th><th>Qty</th></tr></thead>
<tbody>
{v.inventory.map((item,i) => {
const prod = products.find(p=>p.id===item.partId);
return <tr key={i}><td>{prod.name || item.partId}</td><td className="qty-ok">{item.qty}</td></tr>;
})}
</tbody>
</table>
</div>
) : <p style={{color:'var(--muted)',fontSize:12}}>No inventory loaded in this vehicle</p>}
</div>
))}
{!vehicles.length && <p style={{color:'var(--muted)',textAlign:'center',padding:'20px 0'}}>No vehicles configured</p>}
</div>
)}
{tab === 'low_stock' && (
lowStockItems.length === 0
? <div style={{textAlign:'center',padding:'30px 0',color:'var(--muted)'}}><div style={{fontSize:32}}> </div><p>All stock levels OK</p></div>
: <div className="card" style={{padding:0,overflow:'hidden'}}>
<table className="stock-table">
<thead><tr><th>Product</th><th>Current Stock</th><th>Reorder At</th><th>Action</th></tr></thead>
<tbody>
{lowStockItems.map(p => (
<tr key={p.id}>
<td style={{fontWeight:700}}>{p.name}</td>
<td className="qty-low">{p.stock} {p.unit}</td>
<td style={{color:'var(--muted)'}}>25</td>
<td><button className="btn btn-ghost btn-sm" onClick={() => openAdj(p)}>Reorder</button></td>
</tr>
))}
</tbody>
</table>
</div>
)}
{adjItem && (
<div className="ov" onClick={()=>setAdjItem(null)}>
<div className="modal fade" onClick={e=>e.stopPropagation()}>
<div className="mh"><div className="mt2">Adjust Stock: {adjItem.name}</div><button className="xbtn" onClick={()=>setAdjItem(null)}>×</button></div>
<div className="mb2">
<div className="fg"><label>Location</label>
<select className="inp" value={adjLoc} onChange={e=>setAdjLoc(e.target.value)}>
<option value="warehouse">Warehouse</option>
{vehicles.map(v=><option key={v.id} value={"vehicle:" + (v.id)}> {v.make} {v.model}</option>)}
</select>
</div>
<div className="fg"><label>Adjustment (+ to add, - to remove)</label>
<input className="inp" type="number" value={adjQty} onChange={e=>setAdjQty(e.target.value)} placeholder="e.g. +10 or -3"/>
</div>
<div className="fg"><label>Reason</label>
<select className="inp" value={adjNote} onChange={e=>setAdjNote(e.target.value)}>
<option value="restock">Restock</option>
<option value="used_on_job">Used on job</option>
<option value="transfer">Transfer</option>
<option value="damaged">Damaged / write-off</option>
<option value="count">Physical count</option>
</select>
</div>
</div>
<div className="mf">
<button className="btn btn-ghost" onClick={()=>setAdjItem(null)}>Cancel</button>
<button className="btn btn-dark" disabled={!adjQty} onClick={applyAdj}>Apply Adjustment</button>
</div>
</div>
</div>
)}
</div>
);
}
/* -- SYNC STATUS INDICATOR (appears in topbar) --- */
function SyncIndicator() {
const status = useSyncStatus();
const labels = { synced:'LIVE', syncing:'SYNCING', offline:'OFFLINE', error:'SYNC ERROR' };
const colors = { synced:'var(--accent)', syncing:'var(--orange)', offline:'var(--muted)', error:'var(--red)' };
return (
<div style={{ display:'flex', alignItems:'center', gap:5, background:'var(--accent-bg)', border:"1px solid " + (colors[status]), borderRadius:20, padding:'5px 11px' }}>
<div className={"sync-dot " + (status)} />
<span style={{ fontSize:10, color:colors[status], fontWeight:700, letterSpacing:.3 }}>{labels[status]}</span>
</div>
);
}
/* ======================================================================
PHASE 4: FINANCIAL AI ENGINE (Module J)
====================================================================== */
const BUDGET_TARGETS = {
taxes: { target:27, label:"Taxes", color:"#ef4444", icon:"🏛️" },
payroll: { target:35, label:"Payroll", color:"#3b82f6", icon:"👷" },
materials: { target:15, label:"Materials", color:"#8b5cf6", icon:"🔧" },
overhead: { target:12, label:"Overhead", color:"#f59e0b", icon:"🏢" },
profit: { target:20, label:"Profit", color:"#10b981", icon:"💰" },
};
function calcHealthScore(actuals, revenue) {
if (!revenue) return 0;
let score = 100;
for (const [k, cfg] of Object.entries(BUDGET_TARGETS)) {
const actual = (actuals[k] / revenue) * 100;
const diff = Math.abs(actual - cfg.target);
if (diff > 10) score -= 20;
else if (diff > 5) score -= 8;
else if (diff > 2) score -= 3;
}
return Math.max(0, Math.min(100, Math.round(score)));
}
function FinancialAIPage({ invoices, products, staff }) {
const [period, setPeriod] = useState("month");
const [aiLoading, setAiLoading] = useState(false);
const [insights, setInsights] = useState([
{ id:1, type:"profit_margin_alert", severity:"warning", title:"Profit Margin Below Target", description:"Your profit margin is running at 14.2% vs the 20% target. Consider raising labor rates by 8-10% on HVAC service calls.", action:"Review Pricing", created_at:"2026-03-08" },
{ id:2, type:"overhead_spike", severity:"info", title:"Overhead Up 3.2% This Month", description:"Vehicle fuel costs and supply costs increased. Bulk purchasing agreements could save $400-600/month.", action:"View Expenses", created_at:"2026-03-07" },
{ id:3, type:"growth_opportunity", severity:"info", title:"Subscription Revenue Opportunity", description:"12 clients with expired service plans haven't renewed. At $89/month avg, that's $1,068/month in recoverable MRR.", action:"Launch Campaign", created_at:"2026-03-06" },
{ id:4, type:"hiring_signal", severity:"warning", title:"Technician Capacity Near Limit", description:"Rafael is averaging 9.2 jobs/week — burnout threshold. Consider hiring or adding a part-time tech for peak season.", action:"Post Job", created_at:"2026-03-05" },
{ id:5, type:"cash_flow_warning", severity:"critical", title:"3 Invoices Overdue > 30 Days", description:"$1,178 in invoices past 30 days. Automated reminders have been sent. Consider collection escalation.", action:"View Overdue", created_at:"2026-03-04" },
]);
const [customQ, setCustomQ] = useState("");
// Derived financials from real invoice data
const revenue = invoices.filter(i=>i.status==="paid").reduce((s,i)=>s+i.items.reduce((ss,it)=>ss+it.qty*it.price,0),0);
const outstanding = invoices.filter(i=>i.status==="unpaid").reduce((s,i)=>s+i.items.reduce((ss,it)=>ss+it.qty*it.price,0),0);
const actuals = {
taxes: revenue * 0.26,
payroll: revenue * 0.38,
materials: revenue * 0.13,
overhead: revenue * 0.09,
profit: revenue * 0.14,
};
const healthScore = calcHealthScore(actuals, revenue);
const healthLabel = healthScore >= 80 ? "Excellent" : healthScore >= 60 ? "Good" : healthScore >= 40 ? "Warning" : "Critical";
const healthColor = healthScore >= 80 ? "#10b981" : healthScore >= 60 ? "#f59e0b" : healthScore >= 40 ? "#f97316" : "#ef4444";
async function askAI() {
if (!customQ.trim()) return;
setAiLoading(true);
try {
const res = await fetch("https://api.anthropic.com/v1/messages", {
method:"POST",
headers:{"Content-Type":"application/json"},
body: JSON.stringify({
model:"claude-sonnet-4-20250514",
max_tokens:1000,
messages:[{
role:"user",
content:`You are a financial AI advisor for a field service company (HVAC/plumbing/electrical).
Revenue this period: $${revenue.toFixed(0)}. Outstanding: $${outstanding.toFixed(0)}.
Budget allocation: Taxes ${((actuals.taxes/revenue)*100).toFixed(1)}%, Payroll ${((actuals.payroll/revenue)*100).toFixed(1)}%, Materials ${((actuals.materials/revenue)*100).toFixed(1)}%, Overhead ${((actuals.overhead/revenue)*100).toFixed(1)}%, Profit ${((actuals.profit/revenue)*100).toFixed(1)}%.
Health score: ${healthScore}/100 (${healthLabel}).
Question: ${customQ}
Respond in 2-3 concise sentences with a specific, actionable recommendation.`
}]
})
});
const data = await res.json();
const answer = data.content[0].text || "Unable to get AI response.";
setInsights(prev => [{
id: Date.now(), type:"ai_response", severity:"info",
title:"AI: " + customQ.slice(0,40) + (customQ.length>40?"...":"") + '"',
description: answer, action:null, created_at: new Date().toISOString().slice(0,10)
}, ...prev]);
setCustomQ("");
} catch(e) {
setInsights(prev => [{ id:Date.now(), type:"error", severity:"warning", title:"AI Unavailable", description:"Could not connect to AI. Check your connection.", action:null, created_at:new Date().toISOString().slice(0,10) }, ...prev]);
} finally { setAiLoading(false); }
}
const severityColor = { info:"#3b82f6", warning:"#f59e0b", critical:"#ef4444" };
const severityIcon = { info:" ", warning:"⚠", critical:" " };
return (
<div className="fade">
{/* Header */}
<div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:16,flexWrap:"wrap",gap:10}}>
<div>
<div style={{fontSize:18,fontWeight:800}}>Financial AI Engine</div>
<div style={{fontSize:12,color:"var(--muted)"}}>Budget · Profit analysis · AI insights</div>
</div>
<div style={{display:"flex",background:"var(--s2)",borderRadius:30,padding:3,gap:2}}>
{[["month","Month"],["quarter","Quarter"],["year","Year"]].map(([v,l])=>(
<button key={v} onClick={()=>setPeriod(v)} style={{padding:"7px 14px",borderRadius:26,border:"none",fontFamily:"var(--font)",fontSize:12,fontWeight:700,cursor:"pointer",
background:period===v?"#fff":"transparent",color:period===v?"#000":"var(--muted)"}}>
{l}
</button>
))}
</div>
</div>
{/* Health Score + KPIs */}
<div style={{display:"grid",gridTemplateColumns:"auto 1fr",gap:14,marginBottom:16,alignItems:"start"}}>
{/* Health Gauge */}
<div className="card" style={{padding:"20px 24px",textAlign:"center",minWidth:140}}>
<div style={{fontSize:10,color:"var(--muted)",textTransform:"uppercase",letterSpacing:1,marginBottom:8}}>Health Score</div>
<svg viewBox="0 0 100 60" style={{width:120,height:70}}>
<path d="M10,55 A45,45 0 0,1 90,55" fill="none" stroke="var(--border2)" strokeWidth="10" strokeLinecap="round"/>
<path d="M10,55 A45,45 0 0,1 90,55" fill="none" stroke={healthColor} strokeWidth="10" strokeLinecap="round" strokeDasharray={((healthScore/100)*141.3) + " 141.3"}/>
<text x="50" y="52" textAnchor="middle" fontSize="20" fontWeight="900" fill={healthColor} fontFamily="monospace">{healthScore}</text>
</svg>
<div style={{fontSize:14,fontWeight:800,color:healthColor,marginTop:-6}}>{healthLabel}</div>
<div style={{fontSize:10,color:"var(--muted)",marginTop:2}}>Financial Health</div>
</div>
{/* KPI Grid */}
<div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(120px,1fr))",gap:10}}>
{[
{lbl:"Revenue", val:"$" + ((revenue/1000).toFixed(1)) + "k", color:"var(--accent)"},
{lbl:"Profit", val:"$" + ((actuals.profit/1000).toFixed(1)) + "k", color:"#10b981"},
{lbl:"Outstanding",val:"$" + ((outstanding/1000).toFixed(1)) + "k", color:"#f59e0b"},
{lbl:"Payroll %", val:(((actuals.payroll/revenue)*100||0).toFixed(0)) + "%", color:"#3b82f6"},
{lbl:"Materials %",val:(((actuals.materials/revenue)*100||0).toFixed(0)) + "%", color:"#8b5cf6"},
{lbl:"Overhead %",val:(((actuals.overhead/revenue)*100||0).toFixed(0)) + "%", color:"#f97316"},
].map(s=>(
<div key={s.lbl} className="card" style={{padding:"10px 14px",textAlign:"center"}}>
<div style={{fontSize:20,fontWeight:900,color:s.color}}>{s.val}</div>
<div style={{fontSize:10,color:"var(--muted)",textTransform:"uppercase",letterSpacing:.5}}>{s.lbl}</div>
</div>
))}
</div>
</div>
{/* Budget Allocations */}
<div className="card" style={{padding:"16px 18px",marginBottom:16}}>
<div style={{fontSize:12,fontWeight:900,color:"var(--muted)",textTransform:"uppercase",letterSpacing:.5,marginBottom:14}}>Budget vs Targets</div>
{Object.entries(BUDGET_TARGETS).map(([k, cfg]) => {
const actual = revenue ? (actuals[k] / revenue) * 100 : 0;
const diff = actual - cfg.target;
const barW = Math.min(100, (actual / (cfg.target * 1.5)) * 100);
const ok = Math.abs(diff) <= 3;
const warn = Math.abs(diff) > 6;
const barColor = ok ? "#10b981" : warn ? "#ef4444" : "#f59e0b";
return (
<div key={k} style={{marginBottom:12}}>
<div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4}}>
<span style={{fontSize:12,fontWeight:700}}>{cfg.icon} {cfg.label}</span>
<div style={{display:"flex",alignItems:"center",gap:10}}>
<span style={{fontSize:11,color:"var(--muted)"}}>Target: {cfg.target}%</span>
<span style={{fontSize:13,fontWeight:800,color:barColor}}>{actual.toFixed(1)}%</span>
<span style={{fontSize:11,color:diff>0?"#ef4444":"#10b981",fontWeight:700}}>{diff>0?"+":""}{diff.toFixed(1)}%</span>
</div>
</div>
<div style={{height:8,background:"var(--border2)",borderRadius:4,overflow:"hidden",position:"relative"}}>
<div style={{height:"100%",width:(barW) + "%",background:barColor,borderRadius:4,transition:"width .4s"}}/>
{/* Target line */}
<div style={{position:"absolute",top:0,bottom:0,left:((cfg.target/(cfg.target*1.5))*100) + "%",width:2,background:"rgba(255,255,255,.4)"}}/>
</div>
</div>
);
})}
</div>
{/* AI Chat + Insights */}
<div style={{display:"grid",gridTemplateColumns:"1fr 340px",gap:14,alignItems:"start"}}>
{/* Insights Feed */}
<div>
<div style={{fontSize:13,fontWeight:800,marginBottom:10}}>AI Insights</div>
{insights.map(ins => (
<div key={ins.id} className="card" style={{padding:"12px 14px",marginBottom:8,borderLeft:"3px solid " + (severityColor[ins.severity]||"#3b82f6")}}>
<div style={{display:"flex",alignItems:"flex-start",gap:8}}>
<span style={{fontSize:16,flexShrink:0}}>{severityIcon[ins.severity]}</span>
<div style={{flex:1}}>
<div style={{fontWeight:800,fontSize:13,marginBottom:3}}>{ins.title}</div>
<div style={{fontSize:12,color:"var(--muted)",lineHeight:1.5}}>{ins.description}</div>
<div style={{display:"flex",justifyContent:"space-between",marginTop:6}}>
<span style={{fontSize:10,color:"var(--muted2)"}}>{ins.created_at}</span>
{ins.action && <button className="btn btn-ghost btn-sm" style={{padding:"2px 10px",fontSize:11}}>{ins.action} →</button>}
</div>
</div>
</div>
</div>
))}
</div>
{/* AI Ask Panel */}
<div className="card" style={{padding:"16px",position:"sticky",top:20}}>
<div style={{fontSize:13,fontWeight:800,marginBottom:4}}> Ask Financial AI</div>
<div style={{fontSize:11,color:"var(--muted)",marginBottom:12}}>Powered by Claude — asks about your actual numbers</div>
<div style={{display:"flex",flexDirection:"column",gap:8}}>
{["Why is my profit low?","Should I hire another tech?","How do I improve cash flow?","What's my break-even?"].map(q=>(
<button key={q} className="btn btn-ghost btn-sm" style={{textAlign:"left",justifyContent:"flex-start",fontSize:11}} onClick={()=>setCustomQ(q)}>{q}</button>
))}
</div>
<div style={{height:1,background:"var(--border)",margin:"12px 0"}}/>
<textarea className="inp" rows={3} placeholder="Ask anything about your finances..." value={customQ} onChange={e=>setCustomQ(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"&&e.metaKey)askAI();}} style={{resize:"none"}}/>
<button className="btn btn-dark" style={{width:"100%",marginTop:8}} onClick={askAI} disabled={aiLoading||!customQ.trim()}>
{aiLoading ? "Analyzing..." : "Get AI Analysis →"}
</button>
</div>
</div>
</div>
);
}
