{[["browse","🔌 Browse"],["connected","✅ Connected"+(connectedCount>0?" ("+connectedCount+")":"")],["templates","📋 API Templates"],["errors","⚠️ Issues"+(errorCount>0?" ("+errorCount+")":"")]].map(([id,lbl])=>(
<button key={id} className={"tab"+(iTab===id?" active":"")} onClick={()=>setITab(id)}>{lbl}</button>
))}
