<div style={{width:42,height:42,borderRadius:10,background:"var(--orange-bg)",border:"2px solid var(--orange)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,fontWeight:900,color:"var(--orange)",flexShrink:0}}>{fp.name.slice(0,2)}</div>
<div>
