const [newMsg, setNewMsg] = useState("");
const [aiLoading, setAiLoading] = useState(false);
const [aiSugg, setAiSugg] = useState("");
const [aiMode, setAiMode] = useState("reply");
const [aiCustom, setAiCustom] = useState("");
