const cartTotal = cart.reduce((s,i) => s + i.price * i.quantity, 0);
const cartCount = cart.reduce((s,i) => s + i.quantity, 0);
function addToCart(product) {
setCart(p => {
const ex = p.find(i => i.productId === product.id);
if (ex) return p.map(i => i.productId === product.id ? { ...i, quantity: i.quantity + 1 } : i);
return [...p, { productId:product.id, name:product.name, price:product.price, quantity:1 }];
});
}
