<div style={{ fontSize:18, fontWeight:900, color:"var(--accent)" }}>${myInvoices.filter(i=>i.status==="paid").reduce((s,i)=>s+i.items.reduce((a,x)=>a+x.qty*x.price,0),0).toFixed(0)}</div>
